// Extrair dados da mensagem (suporta Evolution API e formato simplificado)
const payload = $input.first().json;

let telefone, mensagem;

if (payload.data?.message) {
  // Formato Evolution API v2
  telefone = (payload.data.key?.remoteJid || '').replace('@s.whatsapp.net', '');
  mensagem = payload.data.message?.conversation || 
             payload.data.message?.extendedTextMessage?.text || '';

  // Ignorar mensagens do próprio bot
  if (payload.data.key?.fromMe) {
    return [{ json: { ignorar: true, motivo: 'mensagem_propria' } }];
  }
} else if (payload.telefone && payload.mensagem) {
  // Formato simplificado (testes via curl)
  telefone = payload.telefone;
  mensagem = payload.mensagem;
} else {
  return [{ json: { ignorar: true, motivo: 'formato_desconhecido' } }];
}

// Limpar telefone
telefone = telefone.replace(/\D/g, '');

if (!telefone || !mensagem) {
  return [{ json: { ignorar: true, motivo: 'dados_incompletos' } }];
}

return [{ json: { telefone, mensagem, timestamp: new Date().toISOString(), ignorar: false } }];

const contato = $('Buscar Contato').first().json;
const dadosMsg = $('Extrair Dados').first().json;
const texto = dadosMsg.mensagem;
const etapaAtual = contato.etapaBot || 'msg1';

// Normalizar texto
const t = texto.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim();

// Detecção de intenções
const opcao1 = t.includes('1') || t.includes('sim') || t.includes('quero') ||
  t.includes('contratar') || t.includes('conhecer') || t.includes('pode') ||
  t.includes('aceito') || t.includes('bora') || t.includes('vamos');

const opcao2 = t.includes('2') || t.includes('tenho site') || t.includes('ja tenho') ||
  t.includes('duvida') || t.includes('pergunta') || t.includes('algumas') ||
  t.includes('como funciona');

const opcao3 = t.includes('3') || t.includes('agora nao') || t.includes('pensar') ||
  t.includes('depois') || t.includes('nao') || t.includes('talvez');

const bloqueio = t.includes('parar') || t.includes('bloquear') || t.includes('spam') || t.includes('sair');

let proximaEtapa = 'atendimento_manual';
let novoStatus = null;
let notificar = false;
let followup = false;

if (bloqueio) {
  proximaEtapa = 'bloqueado';
  novoStatus = 'naoInteresse';
} else {
  switch (etapaAtual) {
    case 'inicio':
    case 'msg1':
      if (opcao1) { proximaEtapa = 'msg2'; novoStatus = 'respondeu'; }
      else if (opcao2) { proximaEtapa = 'msg2b'; novoStatus = 'respondeu'; }
      else if (opcao3) { proximaEtapa = 'msg3c'; novoStatus = 'naoInteresse'; followup = true; }
      else { proximaEtapa = 'msg2'; novoStatus = 'respondeu'; }
      break;
    case 'msg2':
      if (opcao1) { proximaEtapa = 'msg3a'; novoStatus = 'interessado'; notificar = true; }
      else if (opcao2) { proximaEtapa = 'msg3b'; novoStatus = 'respondeu'; }
      else if (opcao3) { proximaEtapa = 'msg3c'; novoStatus = 'pendente_followup'; followup = true; }
      else { proximaEtapa = 'msg3b'; novoStatus = 'respondeu'; }
      break;
    case 'msg2b':
      if (opcao1) { proximaEtapa = 'msg2b_fim'; novoStatus = 'naoInteresse'; }
      else { proximaEtapa = 'msg2'; novoStatus = 'respondeu'; }
      break;
    case 'msg3b':
      if (opcao1) { proximaEtapa = 'msg3a'; novoStatus = 'interessado'; notificar = true; }
      else if (opcao2) { proximaEtapa = 'msg3c'; novoStatus = 'pendente_followup'; followup = true; }
      else if (opcao3) { proximaEtapa = 'msg3c'; novoStatus = 'pendente_followup'; followup = true; }
      else { proximaEtapa = 'msg3c'; novoStatus = 'pendente_followup'; followup = true; }
      break;
    default:
      proximaEtapa = 'atendimento_manual';
      break;
  }
}

return [{
  json: {
    contatoId: contato.id,
    telefone: dadosMsg.telefone,
    nome: contato.nome,
    escritorio: contato.escritorio,
    cidade: contato.cidade,
    areaAtuacao: contato.areaAtuacao,
    etapaAtual,
    proximaEtapa,
    novoStatus,
    notificar,
    followup,
    mensagemOriginal: texto
  }
}];
